def _find_peak_index(arr):
    n = len(arr)
    low = 0
    high = n - 1

    while low < high:
        mid = low + (high - low) // 2
        if arr[mid] < arr[mid + 1]:
            low = mid + 1
        else:
            high = mid
    return low

def _binary_search_increasing(arr, target, low, high):
    while low <= high:
        mid = low + (high - low) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            low = mid + 1
        else:
            high = mid - 1
    return -1

def _binary_search_decreasing(arr, target, low, high):
    while low <= high:
        mid = low + (high - low) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            high = mid - 1
        else:
            low = mid + 1
    return -1

def search_bitonic_array(arr, target):
    n = len(arr)
    if n == 0:
        return -1

    peak_index = _find_peak_index(arr)

    if arr[peak_index] == target:
        return peak_index

    if target > arr[peak_index]:
        return -1 # Target cannot be greater than the peak element

    # Search in the increasing part
    result = _binary_search_increasing(arr, target, 0, peak_index - 1)
    if result != -1:
        return result

    # Search in the decreasing part
    result = _binary_search_decreasing(arr, target, peak_index + 1, n - 1)
    return result
